// Build a query for rentals collection based on the first 13 characters of transactionid
const p = msg.payload || {};
const fullId = String(p.transactionid || msg.transactionid || '');
const shortId = fullId.substring(0, 13);

if (!shortId) {
    node.error('❌ Missing transactionid');
    return null;
}

msg._orderid = shortId;
msg._refundStatus = p.status || msg.status || 'unknown';
msg._refundAmount = p.amount ?? msg.amount ?? 'unknown';
msg._refundDate = p.time || msg.time || new Date().toISOString();
msg._refundStationid = p.stationid || msg.stationid || '';
msg._refundAdmin = p.admin || msg.admin || '';

msg.payload = {
    path: 'rentals',
    query: [
        { fieldPath: 'orderid', opStr: '==', value: shortId }
    ]
};

node.status({ fill: 'blue', shape: 'dot', text: `Query ${shortId}` });
return msg;

// --- Merge refund fields, mark returned, and adjust totalCharged ---

const results = msg.payload;
const orderid = msg._orderid;
const refundStatus = String(msg._refundStatus || 'unknown').trim() || 'unknown';
const refundAmountRaw = msg._refundAmount;
const refundDate = String(msg._refundDate || new Date().toISOString()).trim() || new Date().toISOString();
const refundStationid = String(msg._refundStationid || '').trim();
const refundAdmin = String(msg._refundAdmin || '').trim();

if (!Array.isArray(results) || results.length === 0) {
    node.warn(`⚠️ No rental found for orderid ${orderid}`);
    return null;
}

const rental = results[0];
const currentTotal = parseFloat(rental.totalCharged) || 0;
const normalizedRefundAmount = String(refundAmountRaw ?? '').trim().toLowerCase();
const isFullRefund = normalizedRefundAmount === 'full';
const numericRefundAmount = isFullRefund
    ? currentTotal
    : Math.max(parseFloat(refundAmountRaw) || 0, 0);
const updatedTotal = Math.max(currentTotal - numericRefundAmount, 0);
const returnTime = String(rental.returnTime || '').trim() || refundDate;
const rentalStart = Date.parse(String(rental.rentedAt || rental.rentalTime || ''));
const rentalEnd = Date.parse(returnTime);

const updatedData = {
    status: 'returned',
    refundStatus,
    refundAmount: isFullRefund ? 'full' : numericRefundAmount.toFixed(2),
    refundDate,
    totalCharged: updatedTotal,
    returnTime,
    returnStationid: rental.returnStationid || refundStationid || rental.rentalStationid || '',
    returnModuleid: rental.returnModuleid || rental.rentalModuleid || '',
    returnSlotid: rental.returnSlotid ?? rental.rentalSlotid ?? 0,
    returnLocation: rental.returnLocation || rental.rentalLocation || '',
    returnPlace: rental.returnPlace || rental.rentalPlace || '',
    returnPower: rental.returnPower || rental.rentPower || '',
    returnType: rental.returnType || 'auto-return'
};

if (refundAdmin) {
    updatedData.refundAdmin = refundAdmin;
}

if (Number.isFinite(rentalStart) && Number.isFinite(rentalEnd)) {
    updatedData.rentalPeriod = Math.max(rentalEnd - rentalStart, 0);
}

msg.payload = {
    path: `rentals/${orderid}`,
    content: updatedData,
    merge: true
};

const refundLabel = isFullRefund ? 'full' : `$${numericRefundAmount.toFixed(2)}`;
node.status({
    fill: 'green',
    shape: 'dot',
    text: `Refund ${refundLabel} → returned / total $${updatedTotal.toFixed(2)}`
});

return msg;

// === Build Firestore Query for Force-Close ===
// Finds the rental using the first 13 characters of transactionid

const p = msg.payload || {};
const fullId = String(p.transactionid || msg.transactionid || "");
const shortId = fullId.substring(0, 13);

if (!shortId) {
    node.error("❌ Missing transactionid in message");
    return null;
}

// Preserve meta info for the next node
msg._orderid = shortId;
msg._action = p.action || "refund";
msg._refundStatus = p.status || "pending";
msg._refundAmount = p.amount || "0";
msg._refundDate = p.time || new Date().toISOString();
msg._admin = p.admin || "system";

// Build Firestore query
msg.payload = {
    path: "rentals",
    query: [
        { fieldPath: "orderid", opStr: "==", value: shortId }
    ]
};

node.status({
    fill: "blue",
    shape: "dot",
    text: `Querying orderid ${shortId}`
});

return msg;

const asStr = v => (v == null ? "" : String(v)).trim();
const asNum = v => Number(v || 0);
const nowISO = () => new Date().toISOString();
const toTs = v => (typeof v === "number" ? v : Date.parse(v) || 0);

function normalizeRate(arr) {
  if (!Array.isArray(arr)) return [];
  return arr.map(t => ({
    time: Number(t?.time ?? 0),
    price: Number(t?.price ?? 0)
  }));
}

function extractPricingFromRental(r) {
  if (r?.pricingAtStart && Array.isArray(r.pricingAtStart.rate)) {
    return {
      kioskmode: r.pricingAtStart.kioskmode || null,
      rate: normalizeRate(r.pricingAtStart.rate),
      currency: r.pricingAtStart.currency || r.currency || null,
      symbol: r.pricingAtStart.symbol || r.symbol || null,
      taxrate: Number(r.pricingAtStart.taxrate ?? r.taxrate ?? 0)
    };
  }

  if (r?.pricing && Array.isArray(r.pricing.rate)) {
    return {
      kioskmode: r.pricing.kioskmode || null,
      rate: normalizeRate(r.pricing.rate),
      currency: r.pricing.currency || r.currency || null,
      symbol: r.pricing.symbol || r.symbol || null,
      taxrate: Number(r.pricing.taxrate ?? r.taxrate ?? 0)
    };
  }

  const tiersFromChargePlan = Array.isArray(r?.chargePlan?.tiers)
    ? r.chargePlan.tiers
    : [];

  return {
    kioskmode: r?.chargePlan?.kioskmode || null,
    rate: normalizeRate(tiersFromChargePlan),
    currency: r?.currency || null,
    symbol: r?.symbol || null,
    taxrate: Number(r?.taxrate ?? 0)
  };
}

function computeCharge(pricing, rentalPeriodMs) {
  const out = {
    plan: {
      kioskmode: String(pricing?.kioskmode || '').toUpperCase(),
      type: 'force-close',
      tierIndex: 0,
      tiers: []
    },
    subtotal: 0,
    tax: 0,
    total: 0,
    currency: pricing?.currency || null,
    symbol: pricing?.symbol || null,
    initialCharge: 0,
    overageCharge: 0
  };

  if (!pricing || !Array.isArray(pricing.rate) || pricing.rate.length === 0) {
    return out;
  }

  const tiers = pricing.rate;
  const taxrate = Number(pricing.taxrate || 0);
  const minutes = Math.floor((Number(rentalPeriodMs) || 0) / 60000);

  let tierIndex = 0;
  tiers.forEach((tier, i) => {
    if (minutes > Number(tier.time || 0)) tierIndex = i + 1;
  });

  const selected = tiers[Math.min(tierIndex, tiers.length - 1)] || { price: 0 };
  let totalcharge = Number(selected.price || 0);
  totalcharge = +(totalcharge * (1 + taxrate / 100)).toFixed(2);

  const subtotal = +(totalcharge / (1 + taxrate / 100)).toFixed(2);
  const tax = +(totalcharge - subtotal).toFixed(2);

  const firstTierPrice = Number(tiers[0]?.price || 0);
  const initialCharge = +((firstTierPrice * (1 + taxrate / 100)).toFixed(2));
  const overageCharge = +(totalcharge - initialCharge).toFixed(2);

  return {
    plan: {
      kioskmode: String(pricing.kioskmode || '').toUpperCase(),
      type: 'force-close',
      tierIndex,
      tiers: tiers.map(t => ({ time: +t.time, price: +t.price }))
    },
    subtotal,
    tax,
    total: totalcharge,
    currency: pricing.currency || null,
    symbol: pricing.symbol || null,
    initialCharge,
    overageCharge
  };
}

const transactionid = asStr(msg.transactionid || msg.payload?.transactionid || "");
if (!transactionid) {
  node.warn("❌ Missing transactionid in force-close message");
  return null;
}

const rentals = msg.payload || [];
if (!Array.isArray(rentals) || rentals.length === 0) {
  node.warn(`⚠️ No rentals found for transaction ${transactionid}`);
  return null;
}

const rental = rentals[0];
const pricing = extractPricingFromRental(rental);

if (!pricing || !Array.isArray(pricing.rate) || pricing.rate.length === 0) {
  node.warn(`⚠️ No DB pricing found on rental ${rental.orderid}; force-close will use zero pricing fallback.`);
}

const returnedAt = nowISO();

rental.status = "returned";
rental.returnTime = returnedAt;
rental.returnStationid = rental.rentalStationid;
rental.returnModuleid = rental.rentalModuleid;
rental.returnSlotid = rental.rentalSlotid || 0;
rental.returnLocation = rental.rentalLocation || rental.returnLocation || "";
rental.returnPlace = rental.rentalPlace || rental.returnPlace || "";
rental.returnPower = rental.rentPower || "";
rental.forceClosed = true;

const start = toTs(rental.rentedAt || rental.rentalTime);
const end = toTs(returnedAt);
rental.rentalPeriod = Math.max(end - start, 0);

const bill = computeCharge(pricing, rental.rentalPeriod);
rental.chargePlan = bill.plan;
rental.currency = bill.currency || rental.currency || null;
rental.symbol = bill.symbol || rental.symbol || null;
rental.subtotal = bill.subtotal;
rental.tax = bill.tax;
rental.totalCharged = bill.total;
rental.initialCharge = bill.initialCharge;
rental.overageCharge = bill.overageCharge;

rental.refundStatus = "force-closed";
rental.refundAmount = "0.00";
rental.refundDate = returnedAt;

msg.payload = {
  path: `rentals/${rental.orderid}`,
  content: rental
};

node.status({
  fill: "green",
  shape: "dot",
  text: `Force closed ${rental.orderid} → total $${Number(bill.total || 0).toFixed(2)}`
});

return msg;
